import{_ as a,o as t,c as s,ag as i}from"./chunks/framework.Dn0B0GT3.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"webgl_plan-1.md","filePath":"webgl_plan-1.md"}'),r={name:"webgl_plan-1.md"};function n(o,e,l,c,d,h){return t(),s("div",null,[...e[0]||(e[0]=[i(`<p>Here is a comprehensive architecture review and design blueprint for introducing a hardware-accelerated WebGL2 (and WebGPU-ready) rendering backend to <strong>NanoTermV2</strong>.</p><p>Our goal is to achieve <strong>144Hz+ vsync rendering</strong>, eliminate Garbage Collection (GC) stutters during rapid scrolling, and guarantee <strong>pixel-perfect subpixel rendering</strong>, all while strictly maintaining the zero-dependency, lightweight (&lt;2000 lines) philosophy.</p><hr><h3 id="_1-renderer-interface-design" tabindex="-1">1. Renderer Interface Design <a class="header-anchor" href="#_1-renderer-interface-design" aria-label="Permalink to &quot;1. Renderer Interface Design&quot;">​</a></h3><p><strong>Assessment:</strong><br> Currently, <code>NanoTermV2</code> is a monolith. The terminal state (parser, buffer arrays, cursor) and the presentation layer (<code>ctx.fillText</code>, <code>ctx.fillRect</code>) are tightly interleaved. To support runtime switching and graceful degradation, rendering must be isolated behind an abstraction boundary.</p><p><strong>Recommendation:</strong><br> Extract rendering into an <code>IRenderer</code> interface. The core <code>NanoTermV2</code> class becomes the &quot;State Source of Truth&quot; (handling VT parsing, scrollback, and grid data), while the renderer acts as a &quot;Dumb Consumer.&quot; The terminal pushes data to the renderer; it does not read from it, except for font metric measurements.</p><p><strong>Code Sketch:</strong></p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> IRenderer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Setup backing stores and bind to container</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  attach</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">container</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">options</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Terminal requests dimensions based on font configuration</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  measureChar</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { charWidth, charHeight };</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Terminal triggers grid resize</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  resize</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">cols</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">rows</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Terminal pushes the frame.</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // state: { gridBuffer, cursorX, cursorY, selection, ... }</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // dirtyRows: Set&lt;number&gt; to enable partial GPU uploads</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  render</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">state</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">dirtyRows</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  destroy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Risk:</strong> Duplicating state between the terminal and renderer wastes memory and CPU cycles.<br><strong>Mitigation:</strong> The terminal will manage a single, flat <code>Uint32Array</code> (see Focus Area 3). The renderer maintains no internal buffer state; it directly uploads this shared array to the GPU.</p><hr><h3 id="_2-webgl-text-rendering-pipeline-glyph-atlas" tabindex="-1">2. WebGL Text Rendering Pipeline (Glyph Atlas) <a class="header-anchor" href="#_2-webgl-text-rendering-pipeline-glyph-atlas" aria-label="Permalink to &quot;2. WebGL Text Rendering Pipeline (Glyph Atlas)&quot;">​</a></h3><p><strong>Assessment:</strong><br> Web terminals require a texture atlas for text because WebGL has no native font shaping. However, baking programmatic characters (box-drawing, blocks) into a texture atlas often introduces &quot;subpixel seams&quot; due to texture interpolation and floating-point rounding—the exact issue you solved in Canvas2D with the <code>+0.5px</code> hack.</p><p><strong>Recommendation:</strong><br> Use a <strong>Hybrid Pipeline: Dynamic Atlas + Procedural Math</strong>.</p><ol><li><strong>Dynamic Grid Atlas (Text):</strong> Maintain an offscreen <code>&lt;canvas&gt;</code>. When an unknown text codepoint is parsed, draw it to the offscreen canvas, run your existing <code>_probeGlyph</code> tofu check, and upload it to a 2048x2048 monochrome or RGBA WebGL texture via <code>gl.texSubImage2D</code>. Because it&#39;s a strict monospace grid, allocating slots is an $O(1)$ operation (no complex bin-packing required).</li><li><strong>Atlas Eviction (Clear-on-Full):</strong> If the atlas fills up, simply clear the GPU texture and rebuild it dynamically from the currently visible screen. This takes <code>&lt;2ms</code> and is vastly simpler than LRU tracking.</li><li><strong>Procedural Shaders (Programmatic):</strong> <strong>Do not put U+2500–U+259F or U+2800–U+28FF in the atlas.</strong> Generate them mathematically in the Fragment Shader using intra-cell UV coordinates. This provides infinite resolution and natively solves subpixel seams (exact pixel math) and rounded corners (via Signed Distance Fields).</li></ol><hr><h3 id="_3-gpu-buffer-management-cpu-→-gpu-data-flow" tabindex="-1">3. GPU Buffer Management (CPU → GPU Data Flow) <a class="header-anchor" href="#_3-gpu-buffer-management-cpu-→-gpu-data-flow" aria-label="Permalink to &quot;3. GPU Buffer Management (CPU → GPU Data Flow)&quot;">​</a></h3><p><strong>Assessment:</strong><br> The current <code>Array&lt;Array&lt;{char, fg, bg, flags}&gt;&gt;</code> allocates millions of JS objects during its lifecycle. Scrolling creates and destroys rows, thrashing the V8 Garbage Collector and causing micro-stutters. This structure is also impossible to upload directly to a GPU.</p><p><strong>Recommendation:</strong><br> Flatten the terminal buffer into a packed <strong><code>Uint32Array</code></strong>. To future-proof for TrueColor (24-bit RGB) while maintaining exact byte alignment, use <strong>16 bytes (4x Uint32) per cell</strong>.</p><p><strong>Packed Cell Layout (maps perfectly to <code>GL_RGBA32UI</code>):</strong></p><ul><li><strong>Word 0:</strong> <code>Codepoint (21 bits) | Flags (11 bits)</code></li><li><strong>Word 1:</strong> <code>Foreground Color (32-bit RGBA)</code></li><li><strong>Word 2:</strong> <code>Background Color (32-bit RGBA)</code></li><li><strong>Word 3:</strong> <code>Atlas UV Index (16 bits) | Reserved (16 bits)</code></li></ul><p><strong>Data Flow &amp; Zero-Copy Scrolling:</strong> Upload the <code>Uint32Array</code> into a 2D Data Texture. To solve the &quot;Full redraw on every frame&quot; problem, use a <strong>Ring Buffer</strong> approach:</p><ol><li>When the terminal scrolls, do <em>not</em> shift the data in the <code>Uint32Array</code>.</li><li>Instead, advance a <code>cpu_row_offset</code> pointer and overwrite the oldest row with the new data.</li><li>Call <code>gl.texSubImage2D</code> to upload <em>only</em> the single overwritten row.</li><li>Pass a <code>u_scrollOffset</code> uniform to the shader. The GPU handles the vertical shift visually. This achieves <strong>zero-copy hardware scrolling</strong>.</li></ol><hr><h3 id="_4-shader-architecture" tabindex="-1">4. Shader Architecture <a class="header-anchor" href="#_4-shader-architecture" aria-label="Permalink to &quot;4. Shader Architecture&quot;">​</a></h3><p><strong>Assessment:</strong><br> Canvas2D requires two passes (backgrounds, then text) plus procedural strokes for decorations.</p><p><strong>Recommendation:</strong><br> Use a <strong>Full-Screen Quad</strong> approach. Do not upload geometry (instanced quads) for every character. Draw a single quad (two triangles) covering the entire canvas. The fragment shader does all the heavy lifting in a single pass.</p><p><strong>Fragment Shader Logic (<code>#version 300 es</code>):</strong></p><ol><li><strong>Cell Resolution:</strong> Calculate the logical cell coordinate <code>ivec2 cell = ivec2(v_uv * u_gridSize)</code>. Apply <code>u_scrollOffset</code> to find the physical row in the texture.</li><li><strong>Data Fetch:</strong> Read the cell data via <code>uvec4 cellData = texelFetch(u_gridTex, physicalCell, 0)</code>.</li><li><strong>SGR Inversion:</strong> Decode FG/BG. <code>if ((flags &amp; FLAG_INVERSE) != 0u) { swap(fg, bg); }</code>.</li><li><strong>Procedural Branching:</strong><ul><li>If <code>codepoint</code> is a Box/Block: Calculate shape mathematically using the local intra-cell UV <code>fract(v_uv * u_gridSize)</code>.</li><li>Else: Fetch the atlas UV and sample the glyph atlas <code>texture(u_atlasTex, atlasUV)</code>.</li></ul></li><li><strong>Decorations:</strong> Apply underlines and strikethroughs mathematically based on the local cell UV Y-coordinate. (e.g., <code>if (hasUnderline &amp;&amp; localUV.y &gt; 0.85 &amp;&amp; localUV.y &lt; 0.95) color = fg;</code>)</li><li><strong>Selection/Cursor:</strong> Mix the selection/cursor color at the very end based on uniform bounding boxes.</li></ol><hr><h3 id="_5-webgpu-future-proofing" tabindex="-1">5. WebGPU Future-Proofing <a class="header-anchor" href="#_5-webgpu-future-proofing" aria-label="Permalink to &quot;5. WebGPU Future-Proofing&quot;">​</a></h3><p><strong>Assessment:</strong><br> WebGPU requires strict memory layouts and prefers Storage Buffers over Data Textures for arbitrary array data.</p><p><strong>Recommendation:</strong><br> The <strong>Full-Screen Quad + Flat <code>Uint32Array</code></strong> architecture maps flawlessly to WebGPU.</p><ul><li>In WebGPU, the 2D Data Texture is simply replaced by a <code>&lt;storage, read&gt;</code> Buffer (<code>array&lt;vec4&lt;u32&gt;&gt;</code>).</li><li>The WGSL fragment shader directly indexes the buffer (<code>let cell = grid_buffer[cell_y * cols + cell_x];</code>), eliminating texture coordinate math entirely.</li><li>By designing the WebGL2 implementation around this flat array now, you guarantee a 1:1 migration path to WebGPU.</li></ul><hr><h3 id="_6-performance-analysis" tabindex="-1">6. Performance Analysis <a class="header-anchor" href="#_6-performance-analysis" aria-label="Permalink to &quot;6. Performance Analysis&quot;">​</a></h3><p><strong>Current Canvas2D Bottlenecks Addressed:</strong></p><ol><li><strong>Garbage Collection:</strong> Re-allocating <code>Cell</code> objects and <code>Array.splice</code> operations stall the V8 engine. Fixed via <code>Uint32Array</code> Ring Buffer.</li><li><strong><code>fillText</code> Overhead:</strong> Rendering character-by-character forces the browser to evaluate text baselines and paths thousands of times per frame. Fixed via Glyph Atlas.</li><li><strong>Overdraw:</strong> Redrawing 1,920 cells on every cursor blink. Fixed via <code>dirtyRow</code> tracking.</li></ol><p><strong>Realistic Throughput:</strong> Draw calls drop from ~4000 to exactly <strong>two</strong> per frame (one texture upload, one draw). WebGL will render the full-screen quad in <code>&lt; 0.2ms</code>. Terminal throughput will easily saturate 144Hz monitors even when executing <code>cat /dev/urandom</code>. The bottleneck will shift entirely from the renderer to the WebSocket ingestion / VT parsing speed.</p><hr><h3 id="_7-migration-path-implementation-roadmap" tabindex="-1">7. Migration Path (Implementation Roadmap) <a class="header-anchor" href="#_7-migration-path-implementation-roadmap" aria-label="Permalink to &quot;7. Migration Path (Implementation Roadmap)&quot;">​</a></h3><p>Implementing this as a &quot;big bang&quot; rewrite is risky. Follow this phased approach:</p><p><strong>1. The Memory Refactor (Immediate, Canvas-only)</strong> — ✅ <strong>Completed</strong></p><ul><li>Rip out <code>Array&lt;Array&lt;Cell&gt;&gt;</code> in <code>nanoterm.js</code>.</li><li>Replace it with the 16-byte-per-cell <code>Uint32Array</code>. Update the existing <code>Canvas2D</code> renderer to decode the bitmasks.</li><li><em>Result:</em> Massive CPU speedup and reduced GC footprint with zero visual changes.</li></ul><p><strong>2. Architectural Abstraction</strong> — ✅ <strong>Completed</strong></p><ul><li>Extract the Canvas2D rendering functions into a <code>CanvasRenderer</code> class implementing <code>IRenderer</code>.</li></ul><p><strong>3. WebGL2 Skeleton &amp; Procedural Shaders (Standalone MVP)</strong></p><ul><li>Implement <code>WebGLRenderer</code>. Set up the Full-Screen Quad, Data Texture, and <code>texSubImage2D</code> dirty-row uploads.</li><li>Write the procedural GLSL math for the Block characters and background colors first (ignoring text). Verify pixel-perfect alignment.</li></ul><p><strong>4. Dynamic Glyph Atlas &amp; Integration</strong></p><ul><li>Implement the offscreen Canvas2D to bake requested text codepoints into the WebGL texture.</li><li>Integrate SGR inversion, selection, text decorations, and cursors.</li><li>Add fallback logic: if <code>getContext(&#39;webgl2&#39;)</code> fails, or if <code>webglcontextlost</code> fires, transparently fall back to <code>CanvasRenderer</code>.</li></ul><p><strong>5. Ring Buffer Scrolling</strong></p><ul><li>Transition the CPU grid to a circular buffer to achieve zero-copy hardware scrolling.</li></ul><h3 id="critical-design-decisions-pre-code" tabindex="-1">Critical Design Decisions (Pre-Code) <a class="header-anchor" href="#critical-design-decisions-pre-code" aria-label="Permalink to &quot;Critical Design Decisions (Pre-Code)&quot;">​</a></h3><ol><li><strong>Target WebGL2, not WebGL1:</strong> <code>GL_RGBA32UI</code> integer textures and <code>texelFetch</code> are mandatory for this architecture to remain clean and lightweight without floating-point precision hacks. WebGL2 has ~99% global browser support.</li><li><strong>Strict Physical Pixels:</strong> To avoid blurry glyphs and seams, you must scale the canvas backing store exactly by <code>window.devicePixelRatio</code> and floor/ceil your cell dimensions so that <code>charWidth</code> is an integer number of physical pixels.</li><li><strong>Probing Stays on CPU:</strong> Keep your excellent <code>_probeGlyph</code> (tofu prevention) logic entirely on the CPU. The CPU checks availability; if missing, it simply never requests the atlas to bake it.</li></ol><h3 id="overall-feasibility-assessment" tabindex="-1">Overall Feasibility Assessment <a class="header-anchor" href="#overall-feasibility-assessment" aria-label="Permalink to &quot;Overall Feasibility Assessment&quot;">​</a></h3><p><strong>Highly Feasible.</strong> Because NanoTermV2 already contains a pixel-perfect, self-contained Canvas implementation of box-drawing and PUA probing, you have the exact toolkit needed to populate a GPU atlas. By limiting the GPU scope to a <strong>Full-Screen Quad + Data Texture</strong>, you bypass complex vertex generation and scene graphs entirely. The complete <code>WebGLRenderer</code> class can comfortably be written in <strong>under 800 lines of JavaScript</strong>, honoring your zero-dependency mandate while matching the performance of native desktop emulators like Alacritty.</p>`,55)])])}const u=a(r,[["render",n]]);export{g as __pageData,u as default};
